commands.script:
const buttons = Array.from(document.querySelectorAll('button'));
const targetButton = buttons.find(btn => btn.textContent.includes('更新'));
if (targetButton) {{
    targetButton.click();
    'Button clicked: 更新';
}} else {{
    'Button not found: 更新';
}}

const dropdown = document.querySelector('div[data-baseweb="select"]');
if (dropdown) {
    dropdown.click();
    'Dropdown clicked';
} else {
    'No dropdown found';
}

(() => {{
    const input = document.querySelector('input[type="text"]');
    if (input) {{
        input.focus();
        input.value = 'videos/test_sample_speech.mp4';
        input.dispatchEvent(new Event('input', {{ bubbles: true }}));
        input.dispatchEvent(new Event('change', {{ bubbles: true }}));
        input.blur();
        return 'Text entered: videos/test_sample_speech.mp4';
    }}
    return 'No text input found';
}})();
